mapper.select:
SELECT id, video_id, channel_id, promotion_copy, method, status, result_url, error_message, executed_at, created_at
FROM promotion_record
WHERE id = #{id}

SELECT id, video_id, channel_id, promotion_copy, method, status, result_url, error_message, executed_at, created_at
FROM promotion_record
WHERE video_id = #{videoId}

    AND status = #{status}

ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM promotion_record
WHERE video_id = #{videoId}

    AND status = #{status}

SELECT COUNT(DISTINCT video_id)
FROM promotion_record
WHERE status = #{status}

SELECT COUNT(*)
FROM promotion_record
WHERE created_at >= #{since}

SELECT COUNT(*)
FROM promotion_record
WHERE status = #{status}
  AND created_at >= #{since}
